import{_ as t}from"./chunks/global-char-part.Dg_kBqt-.js";import{_ as o,o as e,c as p,a2 as r}from"./chunks/framework.CkaEw-3u.js";const u=JSON.parse('{"title":"基本的な考え方","description":"","frontmatter":{"title":"基本的な考え方","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/guide/core-concepts.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"ja_JP"}],["meta",{"property":"og:title","content":"基本的な考え方 | Mug Typography Manual"}],["meta",{"property":"og:description","content":"文字をパーツまで分解して動かせる、DaVinci Resolve対応OFXプラグイン Mug Typography のオンラインマニュアル"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/guide/core-concepts.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"基本的な考え方 | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"文字をパーツまで分解して動かせる、DaVinci Resolve対応OFXプラグイン Mug Typography のオンラインマニュアル"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"guide/core-concepts.md","filePath":"guide/core-concepts.md"}'),n={name:"guide/core-concepts.md"};function s(i,a,l,g,c,d){return e(),p("div",null,[...a[0]||(a[0]=[r('<h1 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h1><p>このプラグインには、操作対象となる<strong>3つの階層</strong>があります。</p><table tabindex="0"><thead><tr><th>階層</th><th>説明</th><th>例</th></tr></thead><tbody><tr><td><strong>グローバル</strong></td><td>テキスト全体に一括で適用される設定</td><td>フォント、全体の位置・回転・スケール</td></tr><tr><td><strong>キャラクター</strong></td><td>1 文字ごとに個別に適用できる設定</td><td>特定の文字を大きくする、色を変える</td></tr><tr><td><strong>パーツ</strong></td><td>文字を構成するパス要素ごとの設定</td><td>「だ」の点だけを動かす</td></tr></tbody></table><p>たとえば、グローバルで全体を右に移動しつつ、特定の文字だけをさらに上にずらし、その文字の中の特定パーツだけを回転させる、といった重ね合わせが可能です。</p><h2 id="変形の積み重なり" tabindex="-1">変形の積み重なり <a class="header-anchor" href="#変形の積み重なり" aria-label="Permalink to &quot;変形の積み重なり&quot;">​</a></h2><p>各階層の変形は、Global → Character → Partの順に積み重なり、その結果が描画されます。</p><div class="propagation-formula"><div class="propagation-term"><span class="propagation-symbol">M<sub>Global</sub></span><span class="propagation-value">回転 +10°</span><small>テキスト全体のピボットを中心に</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Character</sub></span><span class="propagation-value">回転 +15°</span><small>その結果へ、文字のピボットを中心に</small></div><span class="propagation-op">×</span><div class="propagation-term"><span class="propagation-symbol">M<sub>Part</sub></span><span class="propagation-value">回転 +20°</span><small>さらに、パーツのピボットを中心に</small></div><span class="propagation-op propagation-op-eq">＝</span><div class="propagation-term propagation-term-result"><span class="propagation-symbol">M<sub>Final</sub></span><span class="propagation-value">向き +45°</span><small>向きは合計45°になる一方、描画位置は各ピボットの位置関係で決まり、単純な足し合わせにはならない</small></div><div class="propagation-demo"><div class="propagation-orbit" aria-hidden="true"><span class="propagation-ring propagation-ring-g"></span><span class="propagation-sun"></span><div class="propagation-system-g"><div class="propagation-earth-system"><span class="propagation-ring propagation-ring-c"></span><span class="propagation-earth"></span><div class="propagation-system-c"><span class="propagation-moon"></span></div></div></div></div><div class="propagation-orbit-copy"><ul class="propagation-legend"><li><span class="propagation-legend-dot propagation-legend-sun"></span>太陽 ＝ Global（テキスト全体）</li><li><span class="propagation-legend-dot propagation-legend-earth"></span>地球 ＝ Character（文字ごと）</li><li><span class="propagation-legend-dot propagation-legend-moon"></span>月 ＝ Part（パーツごと）</li></ul><p class="propagation-demo-caption">地球は太陽のまわりを回り、月はさらに地球のまわりを回ります。太陽から見た月の位置と向きが両方の回転から決まるように、Global・Character・Partの変形も、各階層のピボットを基準として順に掛け合わされます。このため、回転角度は合計できても、最終的な位置は単純な足し算にはなりません。</p></div></div></div><p><img src="'+t+'" alt="Global・Character・Partの各階層で変形が加わる様子"></p><p><em>Global → Character → Partの順に変形が積み重なる様子</em></p><p>色の合成についても同様の優先順位があります。詳細は付録の「<a href="/mug-typography-docs/reference/appendix.html#色の優先順位">色の優先順位</a>」を参照してください。</p><h2 id="パーツ操作が不要な場合" tabindex="-1">パーツ操作が不要な場合 <a class="header-anchor" href="#パーツ操作が不要な場合" aria-label="Permalink to &quot;パーツ操作が不要な場合&quot;">​</a></h2><p>パーツ単位での操作（移動・拡大縮小など）を使わない場合は、Lite版を選択することでクリップのロードや選択動作を軽くできます。Part Settings がインスペクタから省略され、項目数が減るためです。</p><p>目的に合ったプリセットを選ぶことが重要です。詳しくは「<a href="/mug-typography-docs/guide/getting-started.html">使い方</a>」を参照してください。</p><h2 id="インデックスの見方" tabindex="-1">インデックスの見方 <a class="header-anchor" href="#インデックスの見方" aria-label="Permalink to &quot;インデックスの見方&quot;">​</a></h2><p>Character Settingsの<code>Character 1, 2...</code>は、入力テキストの先頭から数えた文字番号です。Part Settingsの<code>Part Setting 1, 2...</code>は、すべての文字を通したパーツ番号です。これらはOutput SettingsやAnimation SettingsのTargetsで使う<code>c1</code>、<code>p1</code>と対応します。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Inspector の各項目には実際の文字と、その文字内で何番目のパーツかが表示されます。番号だけで判断しづらい場合は、ビューアで対象を選択して対応する項目を確認してください。</p></div><hr><p><a id="interface-overview-ja"></a></p>',18)])])}const y=o(n,[["render",s]]);export{u as __pageData,y as default};
